import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Edge implements Comparable<Edge> {
        int u, v;
        long w;
        public Edge(int u, int v, long w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }
        @Override
        public int compareTo(Edge o) {
            return Long.compare(this.w, o.w);
        }
    }
    public static int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }
    public static void unionSet(int[] parent, int[] rank, int x, int y) {
        int rootX = find(parent, x);
        int rootY = find(parent, y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] population = new int[N];
            for (int i = 0; i < N; i++) {
                population[i] = scanner.nextInt();
            }
            Edge[] edges = new Edge[N * (N - 1) / 2];
            int edgeCount = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    edges[edgeCount] = new Edge(i, j, (long) population[i] * population[j]);
                    edgeCount++;
                }
            }
            Arrays.sort(edges, 0, edgeCount);
            int[] parent = new int[N];
            int[] rank = new int[N];
            for (int i = 0; i < N; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
            long totalCost = 0;
            for (int i = 0; i < edgeCount; i++) {
                if (find(parent, edges[i].u) != find(parent, edges[i].v)) {
                    unionSet(parent, rank, edges[i].u, edges[i].v);
                    totalCost += edges[i].w;
                }
            }
            System.out.println(totalCost);
        }
    }
}

